        "citations": []
    },
    {
        "role": "bullet",
        "segment": "Perform personal hygiene (brush teeth, wash face)",
        "citations": []
    },
    {
        "role": "bullet",
        "segment": "Get dressed",
        "citations": []
    },
    {
        "role": "bullet",
        "segment": "Have breakfast",
        "citations": []
    },
    {
        "role": "bullet",
        "segment": "Leave for class or work",
        "citations": []
    },
    {
        "role": "paragraph",
        "segment": "A diagram to capture this process would include states or activities connected by arrows indicating the flow from waking up to leaving for class or work, with possible decision points such as whether to have breakfast or not.",
        "citations": [
            {
                "type": "source_text",
                "content": "A rectangle represents an activity, with an arrow showing transitions from one activity to another. In this example, after activity B is performed,a decision must be made.",
