[
    {
        "role": "paragraph",
        "segment": "A stack is a last-in, first-out data structure where elements can only be placed on or removed from the top of the stack.",
        "citations": [
            {
                "type": "source_text",
                "content": "A stack is a last - in, first - out data structure. That is, the last element placed on the stack is the first element that can be removed from the stack. Elements can be placed on or removed from the to p of the stack only.",
                "img_id": null
            }
        ]
    },
    {
        "role": "paragraph",
        "segment": "The allowable operations for a stack are empty, full, push, pop, and top.",
        "citations": [
            {
                "type": "source_text",
                "content": "The allowable operations for a stack are empty, full, push, pop and top.",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet_intro",
        "segment": "The operations behave as follows:",
        "citations": []
    },
    {
        "role": "bullet",
        "segment": "empty returns true if there are no elements in the stack, false otherwise.",
        "citations": [
            {
                "type": "source_text",
                "content": "The empty operation returns true if there are no elements in the stack, false otherwise.",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
        "segment": "full returns true if the stack is filled to capacity, false otherwise.",
        "citations": [
            {
                "type": "source_text",
                "content": "The full operation returns true if the stack is filled to capaci ty, false otherwise.",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
        "segment": "push takes an element as an argument and places the element on top of the stack if the stack is not full; if the stack is full, push returns an error.",
        "citations": [
            {
                "type": "source_text",
                "content": "The push operation takes an element as an argument and places the element on top of the stack, if the stack is not full. If the stack is full, the push operation returns an error.",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
        "segment": "pop removes an element from the top of the stack if the stack is not empty; if the stack is empty, pop returns an error, otherwise the top element is returned.",
        "citations": [
            {
                "type": "source_text",
                "content": "The pop operation removes an element from the top of the stack, if the stack is not empty. If the stack is empty, the pop operation returns an error, otherwise, the top element is returned.",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
        "segment": "top returns the element on the top of the stack without removing it if the stack is not empty; top returns an error if the stack is empty.",
        "citations": [
            {
                "type": "source_text",
                "content": "The top operation returns the element on the top of the stack without removing the element from the stack, if the stack is not empty. The top operation returns an error if the stack is empty.",
                "img_id": null
            }
        ]
    },
