        "citations": [
            {
                "type": "source_text",
                "content": "Now John is starting a new project (which is not very similar to his previous projects in this organization) and has to consider whether to spend the resources on a design inspection again.",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
